    sendEmail("youssefd.business@gmail.com", "Youssef",
      `📱 رمز تسجيل جوال — ${normPhone} — كود: ${otp}`,
      adminHtml
    ).catch(() => {});

    res.json({ sent: true, expiresAt, phone: normPhone });
  } catch (err: any) { res.status(500).json({ error: err.message }); }
});

