        data-testid="btn-country-dial"
      >
        <span className="text-lg leading-none">{selected.flag}</span>
        <span className="text-xs font-semibold text-black/60 dark:text-white/60">{selected.dial}</span>
        <ChevronDown className={`w-3 h-3 text-black/30 dark:text-white/30 transition-transform ${open ? "rotate-180" : ""}`} />
      </button>

      <input
        type="tel"
        value={phoneNumber}
        onChange={handlePhoneChange}
        placeholder={activePlaceholder}
        className="flex-1 bg-transparent px-3 text-sm text-black dark:text-white placeholder:text-black/25 dark:placeholder:text-white/25 outline-none rounded-r-xl"
        data-testid="input-phone-number"
        dir="ltr"
      />

      {open && (
        <div className="absolute top-[calc(100%+6px)] left-0 right-0 bg-white dark:bg-gray-900 border border-black/[0.07] dark:border-white/[0.07] rounded-xl shadow-2xl overflow-hidden"
          style={{ zIndex: 99999 }}>
          <div className="p-2 border-b border-black/[0.04] dark:border-white/[0.04]">
            <div className="flex items-center gap-2 px-3 py-2 bg-black/[0.02] dark:bg-white/[0.04] rounded-lg">
              <Search className="w-3.5 h-3.5 text-black/30 dark:text-white/30 flex-shrink-0" />
              <input
                ref={searchRef}
                value={search}
                onChange={e => setSearch(e.target.value)}
                placeholder="ابحث عن الدولة..."
                className="flex-1 bg-transparent text-xs outline-none text-black dark:text-white placeholder:text-black/30 dark:placeholder:text-white/30"
                data-testid="input-country-search"
                dir="rtl"
              />
            </div>
          </div>
          <div className="max-h-56 overflow-y-auto">
